import React from 'react';

function Education({ data }) {
  if (!data) return null;

  return (
    <section id="education" className="py-16 md:py-24 bg-white">
      <div className="max-w-7xl mx-auto px-4">
        <p className="text-xs uppercase tracking-widest text-gray-500 font-semibold mb-12">
          Education
        </p>

        <div className="space-y-12">
          {data.map((edu) => (
            <div key={edu.id} className="border-b border-gray-200 pb-12 last:border-0">
              <h3 className="text-2xl font-black text-gray-900 mb-2">
                {edu.degree}
              </h3>
              <p className="text-base text-gray-600 mb-1">
                {edu.institution}
              </p>
              <p className="text-sm text-gray-500 mb-4">{edu.period}</p>
              {edu.details && <p className="text-base text-gray-600 leading-relaxed">{edu.details}</p>}
              {edu.location && <p className="text-base text-gray-600 leading-relaxed">{edu.location}</p>}
            </div>
          ))}
        </div>
      </div>
    </section>
  );
}

export default Education;
